tasks.register("generatePayloadDex", Exec) {
    dependsOn "compileReleaseKotlin", ":common:compileReleaseKotlin"

    def sdkDir = System.getenv("ANDROID_SDK_ROOT")
    def buildToolsDir = new File("${sdkDir}/build-tools")
    def latestVersion = buildToolsDir.listFiles()?.findAll { it.isDirectory() }?.collect { it.name }?.sort()?.last()
    def d8Path = "${sdkDir}/build-tools/${latestVersion}/d8"

    def payloadClassDir = file("build/tmp/kotlin-classes/release")
    def commonClassDir = project(":common").file("build/tmp/kotlin-classes/release")
    def outputDir = file("../dynamic_build/dex")

    // Collect all library dependencies for d8 --lib
    def libClasspath = configurations.releaseCompileClasspath.files.collect { it.absolutePath }
    libClasspath.add("${sdkDir}/platforms/android-34/android.jar")

    doFirst {
        outputDir.mkdirs()
        println "⚡ Speedster Mode: Resolving dependencies and crunching DEX..."
    }

    // Feed d8 everything it needs to avoid desugaring warnings
    def argsList = ["--output", outputDir.absolutePath, "--min-api", "24"]
    libClasspath.each { argsList.add("--lib"); argsList.add(it) }

    // Include all compiled classes from payload and common
    argsList.add(payloadClassDir.absolutePath)
    argsList.add(commonClassDir.absolutePath)

    executable d8Path
    args argsList

    doLast {
        println "✅ Payload DEX generated. Build is now cached for speed."
    }
}

